	&Dvelop_Menu.clear()

	//MODULO PDV
	&PDV_M = RetornaEmpresaModulo.Udp(&EmpCod, ModuloSistema.PDV_M)
	&MEU_CTE = RetornaEmpresaModulo.Udp(&EmpCod, ModuloSistema.MEU_CTE)
	&MEU_NFCE = RetornaEmpresaModulo.Udp(&EmpCod, ModuloSistema.MEU_NFCE)

	&Dvelop_MenuItem = new()
	&Dvelop_MenuItem.id = 'dashboard'
	&Dvelop_MenuItem.tooltip = 'Tela Principal'
	&Dvelop_MenuItem.link = Dashboard.Link()
	&Dvelop_MenuItem.linkTarget = ''
	&Dvelop_MenuItem.iconClass = !"menu-icon fa fa-home"
	&Dvelop_MenuItem.caption = 'Dashboard'
	&Dvelop_Menu.Add(&Dvelop_MenuItem) 

