		//FAVORITOS DA PESSOA
		For Each Order EmpCod, PesCod, FavOrd, FavRotAutNom
			Where EmpCod = &EmpCod
			Where PesCod = &PesCod
			Where FavWebSmart = 'W' or FavWebSmart.IsNull() or FavWebSmart.IsEmpty()

			&RotLin = ''
			&NomeImagem = ''
			For Each Order EmpCod, RotAutCod, RotCod
				Where upper(RotAutCod) = upper(FavRotAutCod) or upper(RotLin) = upper(FavRotAutCod.Trim()) + '.aspx'
				&RotLin = RotLin
				&NomeImagem = RotImgFav
				Exit
			EndFor

			If &RotLin <> ''
				Do Case
					Case Substr(&NomeImagem,1,3) = 'ico'
						&NomeImagem = "menu-icon fal fa-question-circle"
					Case &NomeImagem.IsEmpty()
						&NomeImagem = 'menu-icon glyphicon glyphicon-question-sign'
				EndCase

				//&NomeImagem = "menu-icon glyphicon glyphicon-question-sign"

				&Count += 1						
				&Dvelop_MenuItem = new()
				&Dvelop_MenuItem.id = UPPER(&RotLin) //'Fv'+trim(str(&Count))
				&Dvelop_MenuItem.id = &Dvelop_MenuItem.id.Replace('.ASPX', '')

				&Dvelop_MenuItem.tooltip = ''
				&Dvelop_MenuItem.link = &RotLin
				&Dvelop_MenuItem.linkTarget = ''
				&Dvelop_MenuItem.iconClass = trim(&NomeImagem)
				&Dvelop_MenuItem.caption = trim(FavRotAutNom.ToUpper())
				&Dvelop_Menu.Add(&Dvelop_MenuItem)

			EndIF
		When none
			Do case
				case&PDV_M = 'S'
					//MONITORA PDV
		    		&Dvelop_MenuItem = new()
					&Dvelop_MenuItem.id = '120'
					&Dvelop_MenuItem.tooltip = ''
					&Dvelop_MenuItem.link = 'pdv_m.aspx'
					&Dvelop_MenuItem.linkTarget = ''
					&Dvelop_MenuItem.iconClass = icon_shopping_cart_col.Link()
					&Dvelop_MenuItem.caption = 'MONITORA PDV'
					&Dvelop_Menu.Add(&Dvelop_MenuItem)
					GravaFavorito.Call('ADD', &EmpCod, &PesCod, 'PDV_M', '', 0, '')

					//VENDAS DO PDV
					&Dvelop_MenuItem = new()
					&Dvelop_MenuItem.id = '121'
					&Dvelop_MenuItem.tooltip = ''
					&Dvelop_MenuItem.link = 'wwPedidoPDV.aspx'
					&Dvelop_MenuItem.linkTarget = ''
					&Dvelop_MenuItem.iconClass = icon_shopping_cart_col.Link()
					&Dvelop_MenuItem.caption = 'MONITORA VENDAS'
					&Dvelop_Menu.Add(&Dvelop_MenuItem)
					GravaFavorito.Call('ADD', &EmpCod, &PesCod, 'WWPEDIDOPDV',  '', 0, '')

					//NFCe
					&Dvelop_MenuItem = new()
					&Dvelop_MenuItem.id = '122'
					&Dvelop_MenuItem.tooltip = ''
					&Dvelop_MenuItem.link = 'wwNotasNFCe.aspx'
					&Dvelop_MenuItem.linkTarget = ''
					&Dvelop_MenuItem.iconClass = icon_question_circle_col.Link()
					&Dvelop_MenuItem.caption = 'MONITORA NFCE'
					&Dvelop_Menu.Add(&Dvelop_MenuItem)
					GravaFavorito.Call('ADD', &EmpCod, &PesCod, 'WWNOTASNFCE',  '', 0,'')

					//Monitora Saldo
					&Dvelop_MenuItem = new()
					&Dvelop_MenuItem.id = '123'
					&Dvelop_MenuItem.tooltip = ''
					&Dvelop_MenuItem.link = 'wwSaldo.aspx'
					&Dvelop_MenuItem.linkTarget = ''
					&Dvelop_MenuItem.iconClass = icon_money_col.Link()
					&Dvelop_MenuItem.caption = 'MONITORA SALDO'
					&Dvelop_Menu.Add(&Dvelop_MenuItem)			
					GravaFavorito.Call('ADD', &EmpCod, &PesCod, 'WWSALDO', '',  0,'')

				Case &MEU_NFCE = 'S'

