					&Dvelop_MenuItem.tooltip = ''
					&Dvelop_MenuItem.link = 'wwcte.aspx'
					&Dvelop_MenuItem.linkTarget = ''
					&Dvelop_MenuItem.iconClass = icon_question_circle_col.Link()
					&Dvelop_MenuItem.caption = 'MONITORA CTE'
					&Dvelop_Menu.Add(&Dvelop_MenuItem)
					GravaFavorito.Call('ADD', &EmpCod, &PesCod, 'WWCTE', '', 0,'')

					//MDFe
					&Dvelop_MenuItem = new()
